    public static File validateFile(File file) throws Exception {
        if (file != null) {
            if (file.isDirectory()) {
                if (!file.exists()) {
                    file.mkdirs();
                }
            } else {
                File parentFolder = file.getParentFile();
                if (parentFolder != null && !parentFolder.exists()) {
                    parentFolder.mkdirs();
                }
                file.createNewFile();
            }
        } else {
            throw new Exception("传入 的引用为null！");
        }
        return file;
    }

